import{c as r}from"./chunks/checklist.Dd30d9YA.js";import{C as o,o as a,c as s,a2 as d,E as l,k as n}from"./chunks/framework.TWA1q3r6.js";const p=JSON.parse('{"title":"🙌 3-6M · 运动萌芽期","description":"","frontmatter":{"title":"🙌 3-6M · 运动萌芽期"},"headers":[],"relativePath":"stages/3-6m.md","filePath":"stages/3-6m.md"}'),i={name:"stages/3-6m.md"},b=Object.assign(i,{setup(h){return(c,t)=>{const e=o("ChecklistTable");return a(),s("div",null,[t[0]||(t[0]=d('<h1 id="🙌-3-6m-·-运动萌芽期" tabindex="-1">🙌 3-6M · 运动萌芽期 <a class="header-anchor" href="#🙌-3-6m-·-运动萌芽期" aria-label="Permalink to &quot;🙌 3-6M · 运动萌芽期&quot;">​</a></h1><blockquote><p>某天你会发现，小家伙突然翻了个身，然后自己也吓了一跳。</p><p>小手开始有意识地抓住东西 —— 你的手指、一个摇铃、或者爸爸的眼镜。</p></blockquote><hr><h2 id="🎯-发展里程碑" tabindex="-1">🎯 发展里程碑 <a class="header-anchor" href="#🎯-发展里程碑" aria-label="Permalink to &quot;🎯 发展里程碑&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>科学项目</th><th>在做什么</th><th>每天多久</th><th>来源</th></tr></thead><tbody><tr><td>大运动</td><td><strong>辅助翻身 + 延长Tummy Time</strong></td><td>翻身是第一个自主位移 → 空间认知起点</td><td>30-60min累计</td><td>AAP</td></tr><tr><td>精细运动</td><td><strong>抓握练习</strong></td><td>手-眼协调回路建立，全掌抓握向精细抓握过渡</td><td>融入玩耍时间</td><td>CDC</td></tr><tr><td>语言</td><td><strong>Serve &amp; Return 回应式对话</strong></td><td>宝宝咿呀 → 你模仿并延展 → 强化语言回路</td><td>全天候</td><td>Harvard</td></tr><tr><td>感官</td><td><strong>多质地触摸探索</strong></td><td>触觉是最早成熟的感官，多质地促进体感皮层分化</td><td>安全材质即可</td><td>—</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">和上个阶段有什么不同？ 🔄</p><p>0-3M 是被动接收（看、听、被抱），这个阶段开始<strong>主动出击</strong>（翻、抓、&quot;说话&quot;）。你能明显感受到一个小人格正在形成。</p></div><hr><h2 id="📋-装备采购清单" tabindex="-1">📋 装备采购清单 <a class="header-anchor" href="#📋-装备采购清单" aria-label="Permalink to &quot;📋 装备采购清单&quot;">​</a></h2>',8)),l(e,{stage:"3-6m",categories:n(r)},null,8,["categories"]),t[1]||(t[1]=d('<div class="danger custom-block"><p class="custom-block-title">❌ 这些仍然不需要</p><ul><li><strong>学步车</strong> — 现在讨论还太早，但广告已经开始种草了。AAP明确反对，每年数千例急诊</li><li><strong>早教App/屏幕</strong> — AAP建议18月龄前零屏幕。你的脸就是最好的&quot;屏幕&quot;</li></ul></div><hr><h2 id="📚-推荐绘本-运动萌芽期" tabindex="-1">📚 推荐绘本：运动萌芽期 <a class="header-anchor" href="#📚-推荐绘本-运动萌芽期" aria-label="Permalink to &quot;📚 推荐绘本：运动萌芽期&quot;">​</a></h2><blockquote><p>小手开始会抓了——给他们能抓、能啃、能翻的书。</p></blockquote><table tabindex="0"><thead><tr><th>绘本</th><th>语言</th><th>为什么适合这个阶段</th><th>互动方式</th></tr></thead><tbody><tr><td><em>Pat the Bunny</em> 🐰</td><td>EN</td><td>触摸书鼻祖(1940)，摸兔毛/照镜子/翻页</td><td>抓着宝宝的手去摸</td></tr><tr><td><em>That&#39;s Not My...</em> 系列 🧸</td><td>EN</td><td>Usborne触摸书，每页不同质地(光滑/粗糙/毛茸茸)</td><td>&quot;摸摸看，这个是...&quot;</td></tr><tr><td><em>Dear Zoo</em> 🦁</td><td>EN</td><td>翻翻书，每翻一页出现新动物，&quot;太大了/太凶了&quot;</td><td>翻页时配夸张表情</td></tr><tr><td><em>Where&#39;s Spot?</em> 🐶</td><td>EN/中</td><td>Eric Hill翻翻书经典，藏猫猫概念启蒙</td><td>&quot;Spot在哪里？&quot;翻开找</td></tr><tr><td><em>Brown Bear</em> 🐻</td><td>EN/中</td><td>Bill Martin Jr.，重复句式完美匹配Serve &amp; Return</td><td>等宝宝&quot;回应&quot;再翻页</td></tr><tr><td><em>蹦!</em></td><td>中</td><td>松冈达英，一个字配一个动作，极简但极有效</td><td>念&quot;蹦！&quot;时把宝宝举起来</td></tr><tr><td><em>噗~噗~噗</em></td><td>中</td><td>谷川俊太郎，全是拟声词，宝宝最爱的声音游戏</td><td>配合嘴型和表情</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">选书技巧</p><p>这个阶段选书三原则：<strong>能啃</strong>（硬纸板/布书/防水材质）、<strong>能抓</strong>（小开本或带凸起标签）、<strong>能互动</strong>（翻翻/触摸/镜子）。普通纸质绘本还不到时候。</p></div><hr><h2 id="🌟-这个阶段的小确幸" tabindex="-1">🌟 这个阶段的小确幸 <a class="header-anchor" href="#🌟-这个阶段的小确幸" aria-label="Permalink to &quot;🌟 这个阶段的小确幸&quot;">​</a></h2><p>这时候不需要新买太多东西 —— 0-3M配的夜灯、衣帽架还在发光发热。</p><p>真正的多巴胺来源是：第一次翻身时你们俩的那种惊喜，和每天早上醒来看到宝宝对你笑的那个瞬间。</p><hr><div class="tip custom-block"><p class="custom-block-title">⏰ 采购提醒</p><p>如果之前没赶上大促买安全座椅/婴儿床，研究一下最近的618或双11窗口。同时可以开始关注餐椅 —— 6月龄吃辅食就需要，Stokke Tripp Trapp 大促价差 <strong>¥700+</strong>。详见 <a href="/linyuhan-baby-guide/pricing.html">价格择时</a>。</p></div>',12))])}}});export{p as __pageData,b as default};
